class Solution {
public:
    int kIncreasing(vector<int>& arr, int k) {
        int n = arr.size();
        vector<int> prefix(n + 1, 0);
        for (int i = k; i < n; i++) {
            prefix[i - k] = max(prefix[i - k], arr[i]);
        }
        int res = 0;
        for (int i = 0; i < k; i++) {
            int j = i;
            while (j < n) {
                res += (arr[j] < prefix[j + k]) ? 1 : 0;
                j += k;
            }
        }
        return res;
    }
};
```

